mapper.select:
SELECT ids.employee_id AS employeeId, qe.score AS qualitativeScore, qe.grade AS grade, COALESCE(qe.status, 'NO_INPUT') AS evalStatus FROM (
SELECT #{employeeId} AS employee_id
) ids LEFT JOIN qualitative_evaluation qe ON qe.evaluatee_id = ids.employee_id AND qe.evaluation_level = 3 AND qe.evaluation_period_id = ( SELECT ep.eval_period_id FROM evaluation_period ep WHERE ep.eval_year = #{year} AND ep.eval_sequence = #{evalSequence} ORDER BY ep.start_date DESC LIMIT 1 )

SELECT ids.employee_id AS employeeId, ROUND(AVG(qn.t_score), 1) AS quantitativeScore, qe.score AS qualitativeScore, qe.grade, qe.status AS evalStatus FROM (
SELECT #{employeeId} AS employee_id
) ids LEFT JOIN qualitative_evaluation qe ON qe.evaluatee_id = ids.employee_id AND qe.evaluation_level = 1 AND qe.evaluation_period_id = ( SELECT ep.eval_period_id FROM evaluation_period ep WHERE ep.status = 'IN_PROGRESS' ORDER BY ep.start_date DESC, ep.eval_sequence DESC LIMIT 1 ) LEFT JOIN quantitative_evaluation qn ON qn.employee_id = ids.employee_id AND qn.eval_period_id = ( SELECT ep.eval_period_id FROM evaluation_period ep WHERE ep.status = 'IN_PROGRESS' ORDER BY ep.start_date DESC, ep.eval_sequence DESC LIMIT 1 ) GROUP BY ids.employee_id, qe.score, qe.grade, qe.status

SELECT ids.employee_id AS employeeId, ROUND(AVG(qe.score), 1) AS qualitativeScore, MAX(qe.grade) AS grade, COALESCE(MAX(qe.status), 'NO_INPUT') AS evalStatus FROM (
SELECT #{employeeId} AS employee_id
) ids LEFT JOIN qualitative_evaluation qe ON qe.evaluatee_id = ids.employee_id AND qe.evaluation_level = 2 AND qe.evaluation_period_id = ( SELECT ep.eval_period_id FROM evaluation_period ep WHERE ep.status = 'IN_PROGRESS' ORDER BY ep.start_date DESC, ep.eval_sequence DESC LIMIT 1 ) GROUP BY ids.employee_id
